requirements.capl_script:
/* REQ_01 */
variables
{
  message 730 bodyStatus;
  message 740 gwWarn;
}

on message Body_Status
{
  if (this.DoorFL == 1)
  {
    // Reset payload before setting signals
    int i;
    for (i = 0; i < 8; i++)
    {
      gwWarn.byte(i) = 0;
    }
    gwWarn.dlc = 8;
    gwWarn.DoorOpenWarn = 1;
    output(gwWarn);
  }
}

