/* REQ_05 */
variables
{
  message 700 gwStatus;
  msTimer modeTimer;
}

on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    gwStatus.byte(i) = 0;
  }
  gwStatus.dlc = 8;
  setTimer(modeTimer, 1000);
}

on timer modeTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    gwStatus.byte(i) = 0;
  }
  gwStatus.dlc = 8;
  gwStatus.GatewayMode = 2;
  output(gwStatus);
  setTimer(modeTimer, 1000);
}

/* REQ_06 */
variables
{
  const float SAFE_TEMP = 110.0;
}

on message Engine_Data
{
  if (this.EngineTemp > SAFE_TEMP)
  {
    Gateway_Warnings.HighTempWarn = 1;
    output(Gateway_Warnings);
  }
}

/* REQ_07 */
variables
{
  const float SAFE_TEMP = 110.0;
}

on message Engine_Data
{
  if (this.EngineTemp <= SAFE_TEMP)
  {
    Gateway_Warnings.HighTempWarn = 0;
    output(Gateway_Warnings);
  }
}

/* REQ_08 */
variables
{
  msTimer tCycle;
  float speed;
  int doorAny;
  int temp;
}

on start
{
  setTimer(tCycle, 100);
}

on message Vehicle_Dynamics { speed = this.VehicleSpeed; }
on message Body_Status { doorAny = this.DoorFL || this.DoorFR || this.DoorRL || this.DoorRR; }
on message Engine_Data { temp = this.EngineTemp; }

on timer tCycle
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    Gateway_Warnings.byte(i) = 0;
  }
  Gateway_Warnings.dlc = 8;
  Gateway_Warnings.OverspeedWarn = (speed > 120);
  Gateway_Warnings.DoorOpenWarn  = (speed > 0 && doorAny);
  Gateway_Warnings.HighTempWarn  = (temp > 110);
  output(Gateway_Warnings);
  setTimer(tCycle, 100);
}

/* REQ_09 */
variables
{
  msTimer tTx;
}

on start
{
  setTimer(tTx, 100);
}

on timer tTx
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    Gateway_Warnings.byte(i) = 0;
  }
  Gateway_Warnings.dlc = 8;
  Gateway_Warnings.OverspeedWarn = 1;
  Gateway_Warnings.DoorOpenWarn  = 1;
  Gateway_Warnings.HighTempWarn  = 1;
  output(Gateway_Warnings);
  setTimer(tTx, 100);
}

/* REQ_10 */
variables
{
  int prevFL;
  float speed;
}

on message Vehicle_Dynamics { speed = this.VehicleSpeed; }

on message Body_Status
{
  if (speed > 0 && prevFL == 0 && this.DoorFL == 1)
  {
    // Reset payload before setting signals
    int i;
    for (i = 0; i < 8; i++)
    {
      Gateway_Warnings.byte(i) = 0;
    }
    Gateway_Warnings.dlc = 8;
    Gateway_Warnings.DoorOpenWarn = 1;
    output(Gateway_Warnings);
  }
  prevFL = this.DoorFL;
}
